insert into public.cc_questions (id, module_id, type, title, question, scenario, situation, explanation, correct_answer, correct_answers, correct_order, correct_blanks, correct_path, word_bank, sentence, image_key, image_desc, tags, pool, display_order) values
('ssiap1-hc-p2-ext-q1', 'ssiap1-partie2', 'quiz', 'Article principal ERP', 'Quel article du Code de la Construction et de l''Habitation définit les règles de sécurité ERP ?', null, null, 'Articles R.123-1 et suivants du CCH = règles applicables aux ERP. CO 12 et autres sont des articles du règlement de sécurité (annexes du CCH).', 0, null::integer[], null::integer[], null::text[], null::integer[], null::text[], null, null, null, array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+0 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%')),
('ssiap1-hc-p2-ext-q2', 'ssiap1-partie2', 'quiz', 'Effectif déclencheur catégorie 5', 'En dessous de quel effectif un ERP relève-t-il de la 5ème catégorie ?', null, null, '5ème cat = sous le seuil défini par TYPE (ex : type R 100 personnes, type O 19, type N 19, etc.). Pas de limite unique. Au-dessus = 4ème, 3ème, 2ème ou 1ère cat.', 2, null::integer[], null::integer[], null::text[], null::integer[], null::text[], null, null, null, array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+1 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%')),
('ssiap1-hc-p2-ext-q3', 'ssiap1-partie2', 'quiz', 'Euroclasses réaction', 'Quelle Euroclasse correspond à la meilleure réaction au feu (matériau incombustible) ?', null, null, 'A1 = incombustible (ex : béton, acier, verre). A2 = quasi-incombustible. B/C/D = combustibles à degrés croissants. F = sans performance définie.', 0, null::integer[], null::integer[], null::text[], null::integer[], null::text[], null, null, null, array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+2 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%')),
('ssiap1-hc-p2-ext-q4', 'ssiap1-partie2', 'quiz', 'Désenfumage objectif', 'Quel est l''objectif PRINCIPAL du désenfumage ?', null, null, 'Désenfumage = évacuation des fumées pour : (1) maintenir cheminements praticables, (2) protéger la structure (T° baisse), (3) faciliter l''intervention pompiers.', 1, null::integer[], null::integer[], null::text[], null::integer[], null::text[], null, null, null, array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+3 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%')),
('ssiap1-hc-p2-ext-q5', 'ssiap1-partie2', 'true-false', 'IGH bureaux 28m', 'Un immeuble de bureaux est classé IGH dès que le plancher bas du dernier niveau dépasse 28 m.', null, null, 'VRAI — Seuil IGH bureaux/hôtels/enseignement = 28 m (mesuré du sol accessible aux pompiers au plancher bas du dernier niveau).', 0, null::integer[], null::integer[], null::text[], null::integer[], null::text[], null, null, null, array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+4 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%')),
('ssiap1-hc-p2-ext-q6', 'ssiap1-partie2', 'true-false', '5ème catégorie sans visite', 'Un ERP de 5ème catégorie sans locaux à sommeil n''a aucune visite de la commission de sécurité.', null, null, 'VRAI — 5ème cat sans sommeil dispense de visite périodique. Sauf à l''ouverture, ou en cas de transformation, ou plainte. Avec sommeil = visites prévues.', 0, null::integer[], null::integer[], null::text[], null::integer[], null::text[], null, null, null, array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+5 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%')),
('ssiap1-hc-p2-ext-q7', 'ssiap1-partie2', 'true-false', 'Compartimentage ERP', 'Le compartimentage d''un ERP doit toujours respecter une surface maximale de 800 m² par compartiment.', null, null, 'FAUX — La surface dépend du type d''ERP, de la catégorie, de la présence de sprinkler. Ex : 1500 m² possibles avec sprinkler. Pas de chiffre unique universel.', 1, null::integer[], null::integer[], null::text[], null::integer[], null::text[], null, null, null, array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+6 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%')),
('ssiap1-hc-p2-ext-q8', 'ssiap1-partie2', 'multiple-select', 'Composition commission sécurité', 'Quels membres font OBLIGATOIREMENT partie d''une commission de sécurité communale ?', null, null, 'Maire + SDIS + DDT + police/gendarmerie = membres permanents. L''Église n''a aucun rôle réglementaire. Le directeur d''ERP est invité mais pas membre.', null, array[0,1,2,3]::integer[], null::integer[], null::text[], null::integer[], null::text[], null, null, null, array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+7 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%')),
('ssiap1-hc-p2-ext-q9', 'ssiap1-partie2', 'multiple-select', 'Documents notice sécurité', 'Que contient une notice descriptive de sécurité ?', null, null, 'Notice = doc technique pour la commission : effectifs, moyens, dégagements, désenfumage, isolement, alarme. Pas de programme commercial.', null, array[0,1,3,4]::integer[], null::integer[], null::text[], null::integer[], null::text[], null, null, null, array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+8 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%')),
('ssiap1-hc-p2-ext-q10', 'ssiap1-partie2', 'multiple-select', 'Avantages compartimentage', 'Quels sont les bénéfices du compartimentage ?', null, null, 'Limiter propagation + préserver chemins + faciliter intervention. Le coefficient d''occupation et l''électricité ne sont pas concernés par le compartimentage.', null, array[0,1,3]::integer[], null::integer[], null::text[], null::integer[], null::text[], null, null, null, array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+9 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%')),
('ssiap1-hc-p2-ext-q11', 'ssiap1-partie2', 'find-intruder', 'Pas un type ERP', 'Lequel de ces types ERP N''EXISTE PAS dans la réglementation française ?', null, null, 'Type Q n''existe pas. Bureaux = Type W. J, L, V sont valides. Les types vont de J à Y, plus PA/SG/CTS/REF/PS pour cas particuliers.', 2, null::integer[], null::integer[], null::text[], null::integer[], null::text[], null, null, null, array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+10 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%')),
('ssiap1-hc-p2-ext-q12', 'ssiap1-partie2', 'find-intruder', 'Pas une obligation IGH', 'Laquelle de ces obligations N''EST PAS spécifique aux IGH ?', null, null, 'Évacuation IGH = SECTORISÉE (par compartiment), pas totale. C''est la spécificité IGH : on évacue le compartiment sinistré + 2 voisins, pas tout l''immeuble.', 2, null::integer[], null::integer[], null::text[], null::integer[], null::text[], null, null, null, array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+11 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%')),
('ssiap1-hc-p2-ext-q13', 'ssiap1-partie2', 'scenario', 'Travaux par points chauds', 'Action correcte ?', 'Une entreprise extérieure soude un escalier métallique au 3ème étage. Vous arrivez et constatez : pas de permis de feu, pas d''extincteur à proximité, atmosphère poussiéreuse.', null, 'Permis de feu (GN13) obligatoire AVANT travaux par points chauds. Sans permis = arrêt immédiat. Document écrit, signé donneur d''ordre + exécutant, valable 1 jour.', 1, null::integer[], null::integer[], null::text[], null::integer[], null::text[], null, null, null, array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+12 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%')),
('ssiap1-hc-p2-ext-q14', 'ssiap1-partie2', 'scenario', 'Vérification commission imminente', 'Que faites-vous ?', 'La commission de sécurité passe demain. Le directeur vous demande de "ranger" le registre en supprimant les anomalies récentes.', null, 'Falsifier un registre = infraction pénale. Refuser, archiver l''original, traiter les anomalies réglementairement. La commission préfère un registre honnête à un faux.', 1, null::integer[], null::integer[], null::text[], null::integer[], null::text[], null, null, null, array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+13 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%')),
('ssiap1-hc-p2-ext-q15', 'ssiap1-partie2', 'image-identify', 'Pictogramme rassemblement', 'Ce pictogramme vert ISO 7010 désigne :', null, null, 'E007 — Point de rassemblement. Position obligatoire sur le plan d''évacuation. Communiquée aux pompiers à leur arrivée.', 1, null::integer[], null::integer[], null::text[], null::integer[], null::text[], null, 'assembly', 'ISO 7010 — E007', array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+14 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%')),
('ssiap1-hc-p2-ext-q16', 'ssiap1-partie2', 'image-identify', 'Sortie de secours', 'Ce panneau vert avec personnage et flèche indique :', null, null, 'E003 — Direction issue de secours. Doit être éclairé par BAES, jalonné jusqu''à la sortie finale.', 1, null::integer[], null::integer[], null::text[], null::integer[], null::text[], null, 'exit-direction', 'ISO 7010 — E003', array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+15 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%')),
('ssiap1-hc-p2-ext-q17', 'ssiap1-partie2', 'sequence', 'Étapes ouverture ERP', 'Remettez dans l''ordre les étapes pour ouvrir un nouvel ERP :', null, null, 'Demande → étude → visite/avis → arrêté. L''avis défavorable bloque l''ouverture. Délai légal 4 mois maximum.', null, null::integer[], array[0,1,2,3]::integer[], null::text[], null::integer[], null::text[], null, null, null, array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+16 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%')),
('ssiap1-hc-p2-ext-q18', 'ssiap1-partie2', 'sequence', 'Hiérarchie réglementaire', 'Classez ces textes du PLUS GÉNÉRAL au PLUS PARTICULIER :', null, null, 'Loi > Décret > Arrêté > document spécifique au bâtiment. Cette pyramide guide en cas de doute : la norme la plus haute prime.', null, null::integer[], array[0,1,2,3]::integer[], null::text[], null::integer[], null::text[], null, null, null, array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+17 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%')),
('ssiap1-hc-p2-ext-q19', 'ssiap1-partie2', 'ranking', 'Catégories ERP par effectif', 'Classez ces catégories ERP de l''EFFECTIF LE PLUS ÉLEVÉ au PLUS FAIBLE :', null, null, 'Plus le numéro est petit, plus l''effectif est grand. La 5ème (sous seuil) n''est pas listée ici car elle dépend du type.', null, null::integer[], array[0,1,2,3]::integer[], null::text[], null::integer[], null::text[], null, null, null, array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+18 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%')),
('ssiap1-hc-p2-ext-q20', 'ssiap1-partie2', 'ranking', 'Sévérité Euroclasses', 'Classez les Euroclasses du PLUS PERFORMANT au MOINS PERFORMANT face au feu :', null, null, 'A1 > A2 > B > C > D > E > F. Lettre haute = meilleure réaction au feu. Sous-classes (-s1, -s2, -d0, -d1) précisent fumées/gouttelettes.', null, null::integer[], array[0,1,2,3]::integer[], null::text[], null::integer[], null::text[], null, null, null, array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+19 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%')),
('ssiap1-hc-p2-ext-q21', 'ssiap1-partie2', 'matching', 'Type ERP ↔ activité', 'Associez chaque type ERP à son activité principale :', null, null, 'J = personnes âgées. L = salles polyvalentes. M = magasins. N = restaurants. O = hôtels. R = enseignement. U = soins. À mémoriser pour SSIAP 1.', null, null::integer[], null::integer[], null::text[], null::integer[], null::text[], null, null, null, array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+20 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%')),
('ssiap1-hc-p2-ext-q22', 'ssiap1-partie2', 'matching', 'IGH ↔ destination', 'Associez chaque classe IGH à sa destination :', null, null, 'GH + lettre = type. A=habitation, O=hôtels, R=enseignement, S=archives, U=sanitaire, W=bureaux, Z=mixte. Seuil IGH habitation 50 m, autres 28 m.', null, null::integer[], null::integer[], null::text[], null::integer[], null::text[], null, null, null, array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+21 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%')),
('ssiap1-hc-p2-ext-q23', 'ssiap1-partie2', 'fill-blank', 'Complétez seuils IGH', 'Complétez les seuils :', null, null, 'IGH habitation : 50 m (plancher bas dernier niveau). Autres usages (bureaux, hôtels, enseignement) : 28 m. Au-delà = ITGH (300 m).', null, null::integer[], null::integer[], array['50','28']::text[], null::integer[], array['50','28','100','12','40','60']::text[], 'Un IGH habitation est défini à partir de %1% mètres. Un IGH bureaux à partir de %2% mètres.', null, null, array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+22 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%')),
('ssiap1-hc-p2-ext-q24', 'ssiap1-partie2', 'fill-blank', 'Complétez compartimentage IGH', 'Complétez les règles de compartimentage IGH :', null, null, 'Article GH 10 : 2500 m² max et 3 niveaux max. Parois CF 2 h. Ces seuils découpent l''IGH en zones autonomes.', null, null::integer[], null::integer[], array['2500','3']::text[], null::integer[], array['2500','3','5000','2','1000','5','1500','4']::text[], 'Dans un IGH, chaque compartiment ne doit pas dépasser %1% m² et %2% niveaux superposés.', null, null, array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+23 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%')),
('ssiap1-hc-p2-ext-q25', 'ssiap1-partie2', 'categories', 'Type ERP par activité', 'Classez ces établissements dans le bon type ERP :', null, null, 'Bien classer = appliquer la bonne réglementation. Crèche = R (enseignement/petite enfance). Auberge = O (hébergement).', null, null::integer[], null::integer[], null::text[], null::integer[], null::text[], null, null, null, array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+24 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%')),
('ssiap1-hc-p2-ext-q26', 'ssiap1-partie2', 'decision', 'Demande modification structurelle', 'Arbre de décision :', 'Un locataire de votre ERP veut percer un mur porteur entre deux locaux pour agrandir sa boutique. Il vous dit que ce sont "juste des travaux d''aménagement".', null, 'Mur porteur + compartimentage CF = sécurité. Procédure : analyse → étude → commission → permis de feu → travaux. Skip une étape = engager sa responsabilité.', null, null::integer[], null::integer[], null::text[], array[0,0,0]::integer[], null::text[], null, null, null, array['handcrafted','starter-pack','partie2-ext']::text[], 'challenge', (select coalesce(max(display_order),-1)+1+25 from public.cc_questions q2 where q2.module_id='ssiap1-partie2' and q2.id not like 'ssiap1-hc-p2-ext-%'));
